import Ruleset from './ruleset';
import Value from './value';
import Selector from './selector';
import AtRule from './atrule';
import NestableAtRulePrototype from './nested-at-rule';

const Media = function(value, features, index, currentFileInfo, visibilityInfo) {
    this._index = index;
    this._fileInfo = currentFileInfo;

    const selectors = (new Selector([], null, null, this._index, this._fileInfo)).createEmptySelectors();

    this.features = new Value(features);
    this.rules = [new Ruleset(selectors, value)];
    this.rules[0].allowImports = true;
    this.copyVisibilityInfo(visibilityInfo);
    this.allowRoot = true;
    this.setParent(selectors, this);
    this.setParent(this.features, this);
    this.setParent(this.rules, this);
};

Media.prototype = Object.assign(new AtRule(), {
    type: 'Media',

    ...NestableAtRulePrototype,

    genCSS(context, output) {
        output.add('@media ', this._fileInfo, this._index);

        // Ensure we always emit valid CSS when a media type is directly followed
        // by media features, e.g. `@media print(max-width: 992px)`.
        // Some CSS parsers/minifiers (e.g. lightningcss) treat `print(` as a
        // function token; CSS requires whitespace between the media type and the
        // following `(`.
        //
        // Less represents the media query as a Value, which may wrap a single
        // Anonymous node containing the whole query string. In that specific
        // case we can safely patch the output without affecting other queries.
        const features = this.features;
        if (features && features.value && features.value.length === 1) {
            const node = features.value[0];
            if (node && node.type === 'Anonymous' && typeof node.value === 'string') {
                // `print(` -> `print (` (also handles `screen(` etc)
                node.value = node.value.replace(/\b([a-zA-Z_-]+)\(/g, '$1 (');
            }
        }

        this.features.genCSS(context, output);
        this.outputRuleset(context, output, this.rules);
    },

    eval(context) {
        if (!context.mediaBlocks) {
            context.mediaBlocks = [];
            context.mediaPath = [];
        }

        const media = new Media(null, [], this._index, this._fileInfo, this.visibilityInfo());
        if (this.debugInfo) {
            this.rules[0].debugInfo = this.debugInfo;
            media.debugInfo = this.debugInfo;
        }

        media.features = this.features.eval(context);

        context.mediaPath.push(media);
        context.mediaBlocks.push(media);

        this.rules[0].functionRegistry = context.frames[0].functionRegistry.inherit();
        context.frames.unshift(this.rules[0]);
        media.rules = [this.rules[0].eval(context)];
        context.frames.shift();

        context.mediaPath.pop();

        return context.mediaPath.length === 0 ? media.evalTop(context) :
            media.evalNested(context);
    }
});

export default Media;

